const runId = process.env.ZEALT_RUN_ID;
const baseEmail = process.env.MAGICBELL_EMAIL;
const apiKey = process.env.MAGICBELL_API_KEY;
const apiSecret = process.env.MAGICBELL_SECRET_KEY;

// Parse baseEmail to plus-addressing format
// e.g. admin@gmail.com -> admin+topic-sub-${runId}@gmail.com
const [local, domain] = baseEmail.split('@');
const userEmail = `${local}+topic-sub-${runId}@${domain}`;
const externalId = `user-topic-sub-${runId}`;

console.log('User Email:', userEmail);
console.log('External ID:', externalId);

async function testV1() {
  console.log('\n--- Testing v1 Create User ---');
  try {
    const response = await fetch('https://api.magicbell.com/users', {
      method: 'POST',
      headers: {
        'X-MAGICBELL-API-KEY': apiKey,
        'X-MAGICBELL-API-SECRET': apiSecret,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: JSON.stringify({
        user: {
          external_id: externalId,
          email: userEmail
        }
      })
    });
    console.log('v1 Status:', response.status);
    const text = await response.text();
    console.log('v1 Response:', text);
  } catch (err) {
    console.error('v1 Error:', err);
  }
}

async function testV2() {
  console.log('\n--- Testing v2 Create User ---');
  try {
    const response = await fetch('https://api.magicbell.com/v2/users', {
      method: 'POST',
      headers: {
        'X-MAGICBELL-API-KEY': apiKey,
        'X-MAGICBELL-API-SECRET': apiSecret,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: JSON.stringify({
        external_id: externalId,
        email: userEmail
      })
    });
    console.log('v2 Status:', response.status);
    const text = await response.text();
    console.log('v2 Response:', text);
  } catch (err) {
    console.error('v2 Error:', err);
  }
}

async function run() {
  await testV1();
  await testV2();
}

run();

